const allItems = $input.all();

const metricas = allItems.find(i => i.json.total_triajes !== undefined)?.json
  || { total_triajes: 0, criticos: 0, altos: 0, moderados: 0, bajos: 0 };

const porProfesional = allItems.filter(i => i.json.profesional !== undefined);
const porHora = allItems.filter(i => i.json.hora !== undefined);

const fecha = new Date().toLocaleDateString('es-CO', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

let html = '<!DOCTYPE html><html><head><style>';
html += 'body{font-family:Arial,sans-serif;margin:40px}';
html += 'h1{color:#2c3e50;border-bottom:2px solid #3498db;padding-bottom:10px}';
html += 'h2{color:#34495e;margin-top:30px}';
html += 'table{width:100%;border-collapse:collapse;margin:20px 0}';
html += 'th,td{border:1px solid #ddd;padding:12px;text-align:left}';
html += 'th{background-color:#3498db;color:white}';
html += 'tr:nth-child(even){background-color:#f9f9f9}';
html += '.metric-box{display:inline-block;width:150px;padding:20px;margin:10px;background:#ecf0f1;border-radius:8px;text-align:center}';
html += '.metric-value{font-size:2em;font-weight:bold;color:#2c3e50}';
html += '.metric-label{font-size:0.9em;color:#7f8c8d}';
html += '.critico{color:#e74c3c}.alto{color:#e67e22}.moderado{color:#f39c12}.bajo{color:#27ae60}';
html += '</style></head><body>';

html += '<h1>Reporte Diario de Triajes</h1>';
html += '<p><strong>Fecha:</strong> ' + fecha + '</p>';
html += '<h2>Resumen General</h2>';
html += '<div class="metric-box"><div class="metric-value">' + (metricas.total_triajes || 0) + '</div><div class="metric-label">Total Triajes</div></div>';
html += '<div class="metric-box"><div class="metric-value critico">' + (metricas.criticos || 0) + '</div><div class="metric-label">Criticos</div></div>';
html += '<div class="metric-box"><div class="metric-value alto">' + (metricas.altos || 0) + '</div><div class="metric-label">Altos</div></div>';
html += '<div class="metric-box"><div class="metric-value moderado">' + (metricas.moderados || 0) + '</div><div class="metric-label">Moderados</div></div>';
html += '<div class="metric-box"><div class="metric-value bajo">' + (metricas.bajos || 0) + '</div><div class="metric-label">Bajos</div></div>';

html += '<h2>Triajes por Profesional</h2>';
if (porProfesional.length > 0) {
  html += '<table><tr><th>Profesional</th><th>Cantidad</th></tr>';
  porProfesional.forEach(item => {
    html += '<tr><td>' + (item.json.profesional || 'N/A') + '</td><td>' + (item.json.cantidad_triajes || 0) + '</td></tr>';
  });
  html += '</table>';
} else {
  html += '<p>No hay datos de profesionales</p>';
}

html += '<h2>Distribucion por Hora</h2>';
if (porHora.length > 0) {
  html += '<table><tr><th>Hora</th><th>Cantidad</th></tr>';
  porHora.forEach(item => {
    const hora = new Date(item.json.hora).toLocaleTimeString('es-CO', { hour: '2-digit', minute: '2-digit' });
    html += '<tr><td>' + hora + '</td><td>' + (item.json.cantidad || 0) + '</td></tr>';
  });
  html += '</table>';
} else {
  html += '<p>No hay datos por hora</p>';
}

html += '<p style="margin-top:40px;color:#7f8c8d;font-size:0.8em">Generado automaticamente por el Sistema de Triaje IA</p>';
html += '</body></html>';

return [{ json: { html: html } }];
